5. public class ProductCatalog
6. {
7.     private readonly IProductStore _store;
8.     public ProductCatalog(IProductStore store) => _store = store;
9. 
10.     public void AddProduct(Product p) => _store.Save(p);
11.     public Product? GetProduct(string sku) => _store.FindBySku(sku);
12.     public void UpdatePrice(string sku, decimal newPrice)
13.     {
14.         var p = _store.FindBySku(sku) ?? throw new KeyNotFoundException(sku);
